// OpenClaw New Lead Notification — detect & prepare
// Paginated fetch with watermark-based dedup
//
// MVP trade-off: fetches /leads/{id}/pack per new lead (N+1 pattern).
// Accepted for simplicity and logic reuse — OpenClaw pack contains
// all enrichment (score, rating, next_action, alert) in one call.
// For high-volume scenarios, a batch endpoint would be more efficient.

// === CONFIGURATION — edit these after importing ===
const API_BASE = 'CONFIGURE_ME'; // e.g. 'http://localhost:8000'
const API_KEY = 'CONFIGURE_ME';  // OPENCLAW_API_KEY value, or '' for dev

const PAGE_SIZE = 50;
const MAX_PAGES = 20;

const staticData = $getWorkflowStaticData('global');
const lastSeenId = staticData.lastSeenId;

const http = require('http');

function apiFetch(path) {
  return new Promise((resolve, reject) => {
    const headers = { 'Content-Type': 'application/json' };
    if (API_KEY && API_KEY !== 'CONFIGURE_ME') {
      headers['X-API-Key'] = API_KEY;
    }
    http.get(`${API_BASE}${path}`, { headers }, (res) => {
      let body = '';
      res.on('data', chunk => body += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`API ${path} returned ${res.statusCode}`));
          return;
        }
        try { resolve(JSON.parse(body)); }
        catch (e) { reject(new Error(`Invalid JSON from ${path}`)); }
      });
    }).on('error', reject);
  });
}

// First-run seed: set watermark to current max, send nothing
if (lastSeenId === undefined || lastSeenId === null) {
  const leads = await apiFetch('/leads?limit=1');
  if (leads.length > 0) {
    staticData.lastSeenId = leads[0].id;
  }
  // Zero leads in system: leave watermark unset, retry next poll
  return [];
}

// Paginated detection with in-memory dedup
const seenIds = new Set();
const newLeads = [];

for (let page = 0; page < MAX_PAGES; page++) {
  const offset = page * PAGE_SIZE;
  const leads = await apiFetch(`/leads?limit=${PAGE_SIZE}&offset=${offset}`);
  if (leads.length === 0) break;

  let reachedOld = false;
  for (const lead of leads) {
    if (lead.id <= lastSeenId) { reachedOld = true; break; }
    if (!seenIds.has(lead.id)) {
      seenIds.add(lead.id);
      newLeads.push(lead);
    }
  }
  if (reachedOld) break;
  if (leads.length < PAGE_SIZE) break;
}

if (newLeads.length === 0) return [];

// Sort oldest-first for chronological notification
newLeads.sort((a, b) => a.id - b.id);

// Fetch packs and format messages
const results = [];

for (const lead of newLeads) {
  const pack = await apiFetch(`/leads/${lead.id}/pack`);

  // Parse notes field
  const notes = pack.notes || '';
  const noteMap = {};

  if (notes.startsWith('@ext:')) {
    try {
      const ext = JSON.parse(notes.substring(5));
      if (ext.phone) noteMap['phone'] = ext.phone;
      if (ext.metadata) {
        for (const [k, v] of Object.entries(ext.metadata)) {
          noteMap[k.toLowerCase()] = String(v);
        }
      }
    } catch (e) { /* fallback below */ }
  }

  if (Object.keys(noteMap).length === 0) {
    for (const line of notes.split('\n')) {
      const idx = line.indexOf(':');
      if (idx > 0) {
        const key = line.substring(0, idx).trim().toLowerCase();
        const val = line.substring(idx + 1).trim();
        if (val) noteMap[key] = val;
      }
    }
  }

  const phone = noteMap['phone'] || noteMap['telefono'] || noteMap['tel'] || 'N/A';
  const boatType = noteMap['boat type'] || noteMap['tipo'] || noteMap['type'] || 'N/A';
  const eslora = noteMap['length'] || noteMap['eslora'] || noteMap['loa'] || 'N/A';
  const brand = noteMap['brand'] || noteMap['marca'] || noteMap['model'] || 'N/A';

  const lines = [];
  if (pack.alert) { lines.push('\u{1F6A8} URGENTE'); lines.push(''); }
  lines.push('Nuevo lead en Sentyacht');
  lines.push('');
  lines.push(`Nombre: ${pack.name}`);
  lines.push(`Email: ${pack.email}`);
  lines.push(`Telefono: ${phone}`);
  lines.push(`Tipo: ${boatType}`);
  lines.push(`Eslora: ${eslora}`);
  lines.push(`Marca: ${brand}`);
  lines.push(`Score: ${pack.score} (${pack.rating})`);
  lines.push(`Accion: ${pack.next_action}`);
  lines.push(`Fuente: ${pack.source}`);

  results.push({ json: { text: lines.join('\n'), lead_id: pack.lead_id } });
}

return results;

// Update watermark — only runs after successful Telegram send
const staticData = $getWorkflowStaticData('global');
const items = $input.all();
if (items.length === 0) return [];
const maxId = Math.max(...items.map(i => i.json.lead_id));
staticData.lastSeenId = maxId;
return [{ json: { updated: true, lastSeenId: maxId, count: items.length } }];
